import { React, useEffect, useState } from 'react'
import { Box, Button, Container, TextField, Link, Typography, Fade } from '@material-ui/core';
import logo2 from '../images/logo2.png'
import logo1 from '../images/logo1.png'
import logo from '../images/logo1.png'
import urslogo from '../images/urslogo.png'
import { makeStyles } from '@material-ui/styles';
import axios from 'axios';

const useStyle = makeStyles(theme => {
    return {
        root: {
            '& .MuiInputBase-root': {
                marginBottom: theme.spacing(1)
            },
            '& .MuiInputBase-input': {
                padding: theme.spacing(2)
            },
            '& .MuiLink-root': {
                color: '#162276',
            }
        },
        formContainer: {
            display: 'fixed',
            backgroundColor: '#f9fbfd',
            padding: '22px',
            [theme.breakpoints.up('sm')]: {
                display: 'block',
                boxShadow: 'rgb(35 68 101 / 5%) 0px 4px 16px, rgb(35 68 101 / 5%) 0px 4px 4px;',
                maxWidth: '400px',
                borderRadius: '7px',
                marginTop: '10%',
                paddingBottom: '30px',
                backgroundColor: '#ffffff'
            }
        },
        logoContainer: {
            maxWidth: '300px',
            margin: '0 auto'
        },
        logo: {
            width: '100%',
            paddingTop: '10%'
        },
        responsiveLogo: {
            display: 'none',
            [theme.breakpoints.up('md')]: {
                display: 'block'
            }
        },
        responsiveLogo1: {
            display: 'none',
            [theme.breakpoints.only('sm')]: {
                display: 'block'
            }
        },
        responsiveLogo2: {
            display: 'none',
            [theme.breakpoints.down('xs')]: {
                display: 'block'
            }
        },
        form: {
            margin: '0 auto',
            maxWidth: '350px'
        },
        btn: {
            width: '100%',
            margin: '12px 0'
        },
        loading: {
            display: 'flex',
            height: '100%',
            width: '100%',
            zIndex: 1,
            position: 'absolute',
            background: '#f9fbfd',
            top: '-40px'
        },
        loadingImage: {
            width: '200px',
            margin: 'auto'
        }

    }
});

export default function Login() {
    const classes = useStyle();

    const [isPending, setIsPending] = useState(true);
    useEffect(() => {
        setTimeout(() => {
            fetch('http://localhost:3000/')
                .then(setIsPending(false));
        }, 2000);
    }, [])


    const [isLoading, setIsLoading] = useState(false);
    useEffect(() => {
        setTimeout(() => {
            fetch('http://localhost:3000/')
                .then(setIsLoading(true))
        }, 2001);
    }, [])

    const [inputs, setInputs] = useState({
        studentID: '',
        password: ''
    })

    const handleChange = (event) => {
        setInputs({...inputs, [event.target.name]: event.target.value});
    }

    const submitForm = (event) => {
        event.preventDefault();
        const sendInputs = {
            studentID: inputs.studentID,
            password: inputs.password
            
        }

        console.log(sendInputs)
        axios.post('http://localhost:80/api/student/save', inputs)
    }


    return (
        <Box className={classes.root}>
            {isPending &&
                <Fade in='true' >
                    <div className={classes.loading}>
                        <img src={urslogo} className={classes.loadingImage} />
                    </div>
                </Fade>
            }

            {isLoading &&
                <Fade in='true' style={{ transitionDelay: '700ms' }}>
                    <Container className={classes.formContainer}>

                        <div className={classes.logoContainer}>
                            <Box className={classes.responsiveLogo}>
                                <img className={classes.logo} src={logo} alt="URSAC Online logo" />
                            </Box>
                            <Box className={classes.responsiveLogo1}>
                                <img className={classes.logo} src={logo1} alt="URSAC Online logo" />
                            </Box>
                            <Box className={classes.responsiveLogo2}>
                                <img className={classes.logo} src={logo2} alt="URSAC Online logo" />
                            </Box>
                        </div>

                        <form className={classes.form} onSubmit={submitForm} method='POST' >
                            <TextField onChange={handleChange} value={inputs.studentID} placeholder='Student ID' name='studentID' variant='outlined' type='text' fullWidth />
                            <TextField onChange={handleChange} value={inputs.password} placeholder='Password' name='password' variant='outlined' type='password' fullWidth />
                            <Button
                                type='submit'
                                name='save'
                                className={classes.btn}
                                size='large'
                                variant='contained'
                                color='secondary'>
                                LOGIN
                            </Button>

                            <center>
                                <div>
                                    <Typography variant='caption'>
                                        <Link href="#">
                                            Forgot Password?
                                        </Link>
                                    </Typography>
                                </div>
                                <div>
                                    <Typography variant='caption'>
                                        <Link href='/TeacherDashboard'>
                                            Teacher Login.
                                        </Link>
                                    </Typography>
                                </div>
                            </center>

                        </form>
                    </Container>
                </Fade>
            }
        </Box>
    )
}
